module top_module(
    input [3:0] data,
    input [1:0] shift,
    input clk,         // Added the clock input
    output reg [3:0] q
);reg [3:0] shifted_data;
reg [3:0] stage2_out;

always @(*) begin
    case(shift)
        2'b00: shifted_data = data;
        2'b01: shifted_data = {data[0], data[3:1]};
        2'b10: shifted_data = {data[1:0], data[3:2]};
        2'b11: shifted_data = {data[2:0], data[3]};
    endcase
end

always @(posedge clk) begin
    stage2_out <= shifted_data;
end

assign q = stage2_out;

endmodule
